INSERT INTO public.lessons (id, level_id, title, description, xp_reward, theory, tasks, story_intro, story_outro, mini_scene, sort_order) VALUES ('js-1', 'js-basics', 'Переменные', 'let, const, var', 15, 'Переменные хранят данные. let — изменяемая, const — константа. var — устаревший способ. Пример: let name = ''Мир'';', '[{"id":"js-1-1","type":"quiz","question":"Какое ключевое слово создаёт неизменяемую переменную?","options":["const","let","var","fixed"],"correctAnswer":"const"},{"id":"js-1-2","type":"code","question":"Создай переменную age со значением 18","starterCode":"","expectedOutput":"let age = 18;","hint":"Используй let"},{"id":"js-1-3","type":"blocks","question":"Собери объявление константы name = ''JS''","blocks":["''JS'';","name =","const"],"correctOrder":["const","name =","''JS'';"]}]'::jsonb, '[{"id":"js-1-intro-1","speaker":"falstaff","text":"Я Фальстаф. Урок «Переменные» — поехали!","emotion":"happy"},{"id":"js-1-intro-2","speaker":"falstaff","text":"let, const, var","emotion":"think"}]'::jsonb, '[{"id":"js-1-outro-1","speaker":"falstaff","text":"Урок «Переменные» пройден. Молодец!","emotion":"happy"},{"id":"js-1-outro-2","speaker":"falstaff","text":"Готов к следующему вызову?","emotion":"celebrate","choices":[{"text":"Спасибо, Фальстаф!","response":"Всегда пожалуйста. До следующего урока!"},{"text":"Было сложно!","response":"Сложности закаляют кодера. Ты справился!"}]}]'::jsonb, '{"title":"Мини-мир: Переменные","subtitle":"Исследуй точки на карте","background":"room","hotspots":[{"id":"js-1-spot-1","label":"А","x":0.25,"y":0.5,"width":0.16,"height":0.14,"task":{"id":"js-1-ma","type":"quiz","question":"Какое ключевое слово создаёт неизменяемую переменную?","options":["const","let","var","fixed"],"correctAnswer":"const"},"doneLabel":"Готово"},{"id":"js-1-spot-2","label":"Б","x":0.5,"y":0.45,"width":0.16,"height":0.14,"task":{"id":"js-1-mb","type":"quiz","question":"Повтор: Переменные?","options":["Да","Нет"],"correctAnswer":"Да"},"doneLabel":"Готово"},{"id":"js-1-spot-3","label":"В","x":0.75,"y":0.55,"width":0.16,"height":0.14,"task":{"id":"js-1-mc","type":"quiz","question":"Готов дальше?","options":["Да!","Ещё чуть"],"correctAnswer":"Да!"},"doneLabel":"Готово"}]}'::jsonb, 0) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, xp_reward = EXCLUDED.xp_reward, theory = EXCLUDED.theory, tasks = EXCLUDED.tasks, story_intro = EXCLUDED.story_intro, story_outro = EXCLUDED.story_outro, mini_scene = EXCLUDED.mini_scene, sort_order = EXCLUDED.sort_order;
INSERT INTO public.lessons (id, level_id, title, description, xp_reward, theory, tasks, story_intro, story_outro, mini_scene, sort_order) VALUES ('js-2', 'js-basics', 'Типы данных', 'string, number, boolean', 20, 'Основные типы: string (текст), number (число), boolean (true/false). typeof показывает тип переменной.', '[{"id":"js-2-1","type":"quiz","question":"Какой тип у значения ''hello''?","options":["string","text","char","word"],"correctAnswer":"string"},{"id":"js-2-2","type":"quiz","question":"Чему равно typeof 42?","options":["number","integer","digit","int"],"correctAnswer":"number"},{"id":"js-2-3","type":"quiz","question":"Какое значение НЕ является boolean?","options":["''true''","true","false","!true"],"correctAnswer":"''true''"},{"id":"js-2-4","type":"match","question":"Соедини тип данных с примером значения","pairs":[{"left":"string","right":"''hello''"},{"left":"number","right":"42"},{"left":"boolean","right":"false"}]}]'::jsonb, '[{"id":"js-2-intro-1","speaker":"falstaff","text":"Я Фальстаф. Урок «Типы данных» — поехали!","emotion":"happy"},{"id":"js-2-intro-2","speaker":"falstaff","text":"string, number, boolean","emotion":"think"}]'::jsonb, '[{"id":"js-2-outro-1","speaker":"falstaff","text":"Урок «Типы данных» пройден. Молодец!","emotion":"happy"},{"id":"js-2-outro-2","speaker":"falstaff","text":"Готов к следующему вызову?","emotion":"celebrate","choices":[{"text":"Спасибо, Фальстаф!","response":"Всегда пожалуйста. До следующего урока!"},{"text":"Было сложно!","response":"Сложности закаляют кодера. Ты справился!"}]}]'::jsonb, '{"title":"Мини-мир: Типы данных","subtitle":"Исследуй точки на карте","background":"room","hotspots":[{"id":"js-2-spot-1","label":"А","x":0.25,"y":0.5,"width":0.16,"height":0.14,"task":{"id":"js-2-ma","type":"quiz","question":"Какой тип у значения ''hello''?","options":["string","text","char","word"],"correctAnswer":"string"},"doneLabel":"Готово"},{"id":"js-2-spot-2","label":"Б","x":0.5,"y":0.45,"width":0.16,"height":0.14,"task":{"id":"js-2-mb","type":"quiz","question":"Повтор: Типы данных?","options":["Да","Нет"],"correctAnswer":"Да"},"doneLabel":"Готово"},{"id":"js-2-spot-3","label":"В","x":0.75,"y":0.55,"width":0.16,"height":0.14,"task":{"id":"js-2-mc","type":"quiz","question":"Готов дальше?","options":["Да!","Ещё чуть"],"correctAnswer":"Да!"},"doneLabel":"Готово"}]}'::jsonb, 1) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, xp_reward = EXCLUDED.xp_reward, theory = EXCLUDED.theory, tasks = EXCLUDED.tasks, story_intro = EXCLUDED.story_intro, story_outro = EXCLUDED.story_outro, mini_scene = EXCLUDED.mini_scene, sort_order = EXCLUDED.sort_order;
INSERT INTO public.lessons (id, level_id, title, description, xp_reward, theory, tasks, story_intro, story_outro, mini_scene, sort_order) VALUES ('js-3', 'js-basics', 'Условия', 'if, else, else if', 25, 'Условные операторы позволяют выполнять код по условию. if (условие) { ... } else { ... }', '[{"id":"js-3-1","type":"quiz","question":"Что выведет: if (5 > 3) { ''да'' } else { ''нет'' }?","options":["''да''","''нет''","undefined","ошибка"],"correctAnswer":"''да''"},{"id":"js-3-2","type":"debug","question":"Найди ошибку в условии","buggyCode":"if x > 5 { console.log(''big''); }","fixedCode":"if (x > 5) { console.log(''big''); }"},{"id":"js-3-3","type":"blocks","question":"Собери условие if-else","blocks":["} else {","if (x > 0) {","''отрицательное'';","''положительное'';","}"],"correctOrder":["if (x > 0) {","''положительное'';","} else {","''отрицательное'';","}"]},{"id":"js-3-4","type":"fill","question":"Заполни пропуски в условии JavaScript","textParts":["if (score "," 10) { ","(''win''); }"],"fillOptions":["===","=","console.log","prompt"],"correctFill":["===","console.log"]}]'::jsonb, '[{"id":"js-3-intro-1","speaker":"falstaff","text":"Я Фальстаф. Урок «Условия» — поехали!","emotion":"happy"},{"id":"js-3-intro-2","speaker":"falstaff","text":"if, else, else if","emotion":"think"}]'::jsonb, '[{"id":"js-3-outro-1","speaker":"falstaff","text":"Урок «Условия» пройден. Молодец!","emotion":"happy"},{"id":"js-3-outro-2","speaker":"falstaff","text":"Готов к следующему вызову?","emotion":"celebrate","choices":[{"text":"Спасибо, Фальстаф!","response":"Всегда пожалуйста. До следующего урока!"},{"text":"Было сложно!","response":"Сложности закаляют кодера. Ты справился!"}]}]'::jsonb, '{"title":"Мини-мир: Условия","subtitle":"Исследуй точки на карте","background":"room","hotspots":[{"id":"js-3-spot-1","label":"А","x":0.25,"y":0.5,"width":0.16,"height":0.14,"task":{"id":"js-3-ma","type":"quiz","question":"Что выведет: if (5 > 3) { ''да'' } else { ''нет'' }?","options":["''да''","''нет''","undefined","ошибка"],"correctAnswer":"''да''"},"doneLabel":"Готово"},{"id":"js-3-spot-2","label":"Б","x":0.5,"y":0.45,"width":0.16,"height":0.14,"task":{"id":"js-3-mb","type":"quiz","question":"Повтор: Условия?","options":["Да","Нет"],"correctAnswer":"Да"},"doneLabel":"Готово"},{"id":"js-3-spot-3","label":"В","x":0.75,"y":0.55,"width":0.16,"height":0.14,"task":{"id":"js-3-mc","type":"quiz","question":"Готов дальше?","options":["Да!","Ещё чуть"],"correctAnswer":"Да!"},"doneLabel":"Готово"}]}'::jsonb, 2) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, xp_reward = EXCLUDED.xp_reward, theory = EXCLUDED.theory, tasks = EXCLUDED.tasks, story_intro = EXCLUDED.story_intro, story_outro = EXCLUDED.story_outro, mini_scene = EXCLUDED.mini_scene, sort_order = EXCLUDED.sort_order;
INSERT INTO public.lessons (id, level_id, title, description, xp_reward, theory, tasks, story_intro, story_outro, mini_scene, sort_order) VALUES ('js-4', 'js-basics', 'Функции', 'function и параметры', 30, 'Функции позволяют переиспользовать код. Они могут принимать параметры и возвращать результат. Пример: function greet(name) { return ''Привет, '' + name; }', '[{"id":"js-4-1","type":"quiz","question":"Какое ключевое слово используется для объявления функции?","options":["function","func","def","method"],"correctAnswer":"function"},{"id":"js-4-2","type":"code","question":"Создай функцию hello без параметров","starterCode":"","expectedOutput":"function hello()","hint":"Начни с function hello()"},{"id":"js-4-3","type":"fill","question":"Заполни пропуски в функции","textParts":["function sum(a, b) { "," a + b; }"],"fillOptions":["return","console.log","sum","if"],"correctFill":["return"]},{"id":"js-4-4","type":"match","question":"Соедини часть функции с ее ролью","pairs":[{"left":"function","right":"Объявляет функцию"},{"left":"(name)","right":"Параметр функции"},{"left":"return","right":"Возвращает результат"}]}]'::jsonb, '[{"id":"js-4-intro-1","speaker":"falstaff","text":"Я Фальстаф. Урок «Функции» — поехали!","emotion":"happy"},{"id":"js-4-intro-2","speaker":"falstaff","text":"function и параметры","emotion":"think"}]'::jsonb, '[{"id":"js-4-outro-1","speaker":"falstaff","text":"Урок «Функции» пройден. Молодец!","emotion":"happy"},{"id":"js-4-outro-2","speaker":"falstaff","text":"Готов к следующему вызову?","emotion":"celebrate","choices":[{"text":"Спасибо, Фальстаф!","response":"Всегда пожалуйста. До следующего урока!"},{"text":"Было сложно!","response":"Сложности закаляют кодера. Ты справился!"}]}]'::jsonb, '{"title":"Мини-мир: Функции","subtitle":"Исследуй точки на карте","background":"room","hotspots":[{"id":"js-4-spot-1","label":"А","x":0.25,"y":0.5,"width":0.16,"height":0.14,"task":{"id":"js-4-ma","type":"quiz","question":"Какое ключевое слово используется для объявления функции?","options":["function","func","def","method"],"correctAnswer":"function"},"doneLabel":"Готово"},{"id":"js-4-spot-2","label":"Б","x":0.5,"y":0.45,"width":0.16,"height":0.14,"task":{"id":"js-4-mb","type":"quiz","question":"Повтор: Функции?","options":["Да","Нет"],"correctAnswer":"Да"},"doneLabel":"Готово"},{"id":"js-4-spot-3","label":"В","x":0.75,"y":0.55,"width":0.16,"height":0.14,"task":{"id":"js-4-mc","type":"quiz","question":"Готов дальше?","options":["Да!","Ещё чуть"],"correctAnswer":"Да!"},"doneLabel":"Готово"}]}'::jsonb, 3) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, xp_reward = EXCLUDED.xp_reward, theory = EXCLUDED.theory, tasks = EXCLUDED.tasks, story_intro = EXCLUDED.story_intro, story_outro = EXCLUDED.story_outro, mini_scene = EXCLUDED.mini_scene, sort_order = EXCLUDED.sort_order;
INSERT INTO public.lessons (id, level_id, title, description, xp_reward, theory, tasks, story_intro, story_outro, mini_scene, sort_order) VALUES ('js-5', 'js-basics', 'Массивы', 'array и доступ по индексу', 30, 'Массив хранит несколько значений в одном месте. Элементы записываются в квадратных скобках, например: [''HTML'', ''CSS'', ''JS'']. Первый элемент имеет индекс 0.', '[{"id":"js-5-1","type":"quiz","question":"Как записывается массив в JavaScript?","options":["[1, 2, 3]","{1, 2, 3}","(1, 2, 3)","<1, 2, 3>"],"correctAnswer":"[1, 2, 3]"},{"id":"js-5-2","type":"blocks","question":"Собери массив из трех технологий","blocks":["''JS'']","[''HTML'',","''CSS'',"],"correctOrder":["[''HTML'',","''CSS'',","''JS'']"]},{"id":"js-5-3","type":"debug","question":"Исправь ошибку в доступе к элементу массива","buggyCode":"const first = items(0);","fixedCode":"const first = items[0];"},{"id":"js-5-4","type":"match","question":"Соедини пример массива и описание","pairs":[{"left":"items[0]","right":"Первый элемент массива"},{"left":"items.length","right":"Количество элементов"},{"left":"[]","right":"Пустой массив"}]}]'::jsonb, '[{"id":"js-5-intro-1","speaker":"falstaff","text":"Я Фальстаф. Урок «Массивы» — поехали!","emotion":"happy"},{"id":"js-5-intro-2","speaker":"falstaff","text":"array и доступ по индексу","emotion":"think"}]'::jsonb, '[{"id":"js-5-outro-1","speaker":"falstaff","text":"Урок «Массивы» пройден. Молодец!","emotion":"happy"},{"id":"js-5-outro-2","speaker":"falstaff","text":"Готов к следующему вызову?","emotion":"celebrate","choices":[{"text":"Спасибо, Фальстаф!","response":"Всегда пожалуйста. До следующего урока!"},{"text":"Было сложно!","response":"Сложности закаляют кодера. Ты справился!"}]}]'::jsonb, '{"title":"Мини-мир: Массивы","subtitle":"Исследуй точки на карте","background":"room","hotspots":[{"id":"js-5-spot-1","label":"А","x":0.25,"y":0.5,"width":0.16,"height":0.14,"task":{"id":"js-5-ma","type":"quiz","question":"Как записывается массив в JavaScript?","options":["[1, 2, 3]","{1, 2, 3}","(1, 2, 3)","<1, 2, 3>"],"correctAnswer":"[1, 2, 3]"},"doneLabel":"Готово"},{"id":"js-5-spot-2","label":"Б","x":0.5,"y":0.45,"width":0.16,"height":0.14,"task":{"id":"js-5-mb","type":"quiz","question":"Повтор: Массивы?","options":["Да","Нет"],"correctAnswer":"Да"},"doneLabel":"Готово"},{"id":"js-5-spot-3","label":"В","x":0.75,"y":0.55,"width":0.16,"height":0.14,"task":{"id":"js-5-mc","type":"quiz","question":"Готов дальше?","options":["Да!","Ещё чуть"],"correctAnswer":"Да!"},"doneLabel":"Готово"}]}'::jsonb, 4) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, xp_reward = EXCLUDED.xp_reward, theory = EXCLUDED.theory, tasks = EXCLUDED.tasks, story_intro = EXCLUDED.story_intro, story_outro = EXCLUDED.story_outro, mini_scene = EXCLUDED.mini_scene, sort_order = EXCLUDED.sort_order;
